// Парсим Telegram-апдейт в общий формат: { chatId, type, text, payload, user }
// type: 'command' | 'text' | 'callback'
const raw = $input.first().json;

let chatId, fromUser, type, text = null, payload = null, callbackQueryId = null, messageId = null;

if (raw.message) {
  chatId = raw.message.chat.id;
  fromUser = raw.message.from;
  messageId = raw.message.message_id;
  text = (raw.message.text || '').trim();
  if (text.startsWith('/')) {
    type = 'command';
    payload = text.split(/\s+/)[0].toLowerCase();
  } else {
    type = 'text';
  }
} else if (raw.callback_query) {
  chatId = raw.callback_query.message.chat.id;
  fromUser = raw.callback_query.from;
  messageId = raw.callback_query.message.message_id;
  callbackQueryId = raw.callback_query.id;
  type = 'callback';
  payload = raw.callback_query.data;
  text = payload;
} else {
  // не интересующий апдейт — отдаём пустой объект, дальше можно отфильтровать
  return [{ json: { skip: true } }];
}

return [{
  json: {
    skip: false,
    chatId,
    type,
    text,
    payload,
    callbackQueryId,
    messageId,
    user: {
      id: fromUser.id,
      username: fromUser.username || null,
      firstName: fromUser.first_name || null,
      lastName: fromUser.last_name || null,
      fullName: [fromUser.first_name, fromUser.last_name].filter(Boolean).join(' ') || null,
    },
  },
}];

