// =============================================================================
// State machine бронирования.
// Вход:
//   - $('Parse Update').first().json    — событие
//   - $('Upsert Client').first().json   — { id, tg_chat_id, ... }
//   - $('Get State').all()              — [{ step, draft }] или []
//   - $('Get Services').all()           — список услуг
// Выход:
//   {
//     chatId, callbackQueryId, replyText, replyKeyboard,
//     nextStep, draft,
//     bookingToSave: null | { client_id, service_id, starts_at, ends_at }
//   }
// =============================================================================
const evt = $('Parse Update').first().json;
const client = $('Upsert Client').first().json;
const stateRows = $('Get State').all().map(i => i.json);
const services = $('Get Services').all().map(i => i.json);

const current = stateRows[0] || { step: 'idle', draft: {} };
let step = current.step || 'idle';
let draft = (current.draft && typeof current.draft === 'object') ? { ...current.draft } : {};

const out = {
  chatId: evt.chatId,
  callbackQueryId: evt.callbackQueryId,
  replyText: '',
  replyKeyboard: null,
  nextStep: step,
  draft,
  bookingToSave: null,
};

function servicesKeyboard() {
  const rows = services.map(s => ([{
    text: `${s.title} — ${s.price_rub ? s.price_rub + '₽' : ''}`.trim(),
    callback_data: `svc:${s.id}`,
  }]));
  return { inline_keyboard: rows };
}

function datesKeyboard() {
  // Ближайшие 7 дней
  const days = [];
  const now = new Date();
  for (let i = 0; i < 7; i++) {
    const d = new Date(now);
    d.setDate(now.getDate() + i);
    const iso = d.toISOString().slice(0, 10);
    const label = d.toLocaleDateString('ru-RU', { weekday: 'short', day: '2-digit', month: '2-digit' });
    days.push({ text: label, callback_data: `date:${iso}` });
  }
  // По 2 в ряд
  const rows = [];
  for (let i = 0; i < days.length; i += 2) rows.push(days.slice(i, i + 2));
  return { inline_keyboard: rows };
}

function timesKeyboard() {
  // Слоты 10:00–20:00 шаг 30 мин
  const slots = [];
  for (let h = 10; h < 20; h++) {
    for (const m of [0, 30]) {
      const hh = String(h).padStart(2, '0');
      const mm = String(m).padStart(2, '0');
      slots.push({ text: `${hh}:${mm}`, callback_data: `time:${hh}:${mm}` });
    }
  }
  const rows = [];
  for (let i = 0; i < slots.length; i += 4) rows.push(slots.slice(i, i + 4));
  return { inline_keyboard: rows };
}

function reset() {
  step = 'idle';
  draft = {};
}

// --- Команды (имеют приоритет над текущим шагом) ---
if (evt.type === 'command') {
  if (evt.payload === '/start' || evt.payload === '/help') {
    out.replyText =
      'Привет! Я бот записи.\n\n' +
      'Команды:\n' +
      '/book — записаться\n' +
      '/my   — мои записи\n' +
      '/cancel — отменить текущее действие';
    reset();
    out.nextStep = step; out.draft = draft;
    return [{ json: out }];
  }
  if (evt.payload === '/cancel') {
    reset();
    out.replyText = 'Окей, всё отменил. Чтобы начать заново — /book';
    out.nextStep = step; out.draft = draft;
    return [{ json: out }];
  }
  if (evt.payload === '/book') {
    step = 'choose_service';
    draft = {};
    out.replyText = 'Какая услуга интересует?';
    out.replyKeyboard = servicesKeyboard();
    out.nextStep = step; out.draft = draft;
    return [{ json: out }];
  }
  if (evt.payload === '/my') {
    out.replyText = 'Твои записи я покажу в следующем шаге (TODO: SELECT из bookings).';
    out.nextStep = step; out.draft = draft;
    return [{ json: out }];
  }
  out.replyText = 'Не понял команду. Напиши /help';
  out.nextStep = step; out.draft = draft;
  return [{ json: out }];
}

// --- Машина состояний ---
switch (step) {
  case 'idle': {
    out.replyText = 'Чтобы записаться, отправь /book';
    break;
  }
  case 'choose_service': {
    if (evt.type === 'callback' && evt.payload && evt.payload.startsWith('svc:')) {
      const sid = parseInt(evt.payload.slice(4), 10);
      const svc = services.find(s => Number(s.id) === sid);
      if (!svc) {
        out.replyText = 'Не нашёл такую услугу. Выбери ещё раз:';
        out.replyKeyboard = servicesKeyboard();
        break;
      }
      draft.service_id = svc.id;
      draft.service_title = svc.title;
      draft.duration_min = svc.duration_min;
      step = 'choose_date';
      out.replyText = `Услуга: ${svc.title}\nВыбери дату:`;
      out.replyKeyboard = datesKeyboard();
    } else {
      out.replyText = 'Нажми кнопку с услугой:';
      out.replyKeyboard = servicesKeyboard();
    }
    break;
  }
  case 'choose_date': {
    if (evt.type === 'callback' && evt.payload && evt.payload.startsWith('date:')) {
      draft.date = evt.payload.slice(5);
      step = 'choose_time';
      out.replyText = `Дата: ${draft.date}\nВыбери время:`;
      out.replyKeyboard = timesKeyboard();
    } else {
      out.replyText = 'Нажми кнопку с датой:';
      out.replyKeyboard = datesKeyboard();
    }
    break;
  }
  case 'choose_time': {
    if (evt.type === 'callback' && evt.payload && evt.payload.startsWith('time:')) {
      draft.time = evt.payload.slice(5);
      step = 'enter_name';
      const hasName = client.full_name;
      if (hasName) {
        out.replyText = `Записаться как «${client.full_name}»? Если да — напиши "да". Иначе пришли своё ФИО.`;
      } else {
        out.replyText = 'Как тебя зовут? (ФИО)';
      }
    } else {
      out.replyText = 'Нажми кнопку со временем:';
      out.replyKeyboard = timesKeyboard();
    }
    break;
  }
  case 'enter_name': {
    if (evt.type === 'text' && evt.text) {
      const text = evt.text.trim();
      if (text.toLowerCase() === 'да' && client.full_name) {
        draft.full_name = client.full_name;
      } else {
        draft.full_name = text;
      }
      step = 'enter_phone';
      if (client.phone) {
        out.replyText = `Подтвердить телефон ${client.phone}? "да" / новый номер.`;
      } else {
        out.replyText = 'Оставь номер телефона (формат +7XXXXXXXXXX)';
      }
    } else {
      out.replyText = 'Напиши имя текстом';
    }
    break;
  }
  case 'enter_phone': {
    if (evt.type !== 'text' || !evt.text) {
      out.replyText = 'Напиши номер текстом';
      break;
    }
    let phone = evt.text.trim();
    if (phone.toLowerCase() === 'да' && client.phone) phone = client.phone;
    const digits = phone.replace(/\D/g, '');
    if (digits.length < 10) {
      out.replyText = 'Номер выглядит коротким. Пришли в формате +7XXXXXXXXXX';
      break;
    }
    draft.phone = phone;

    // Считаем starts_at / ends_at
    const [hh, mm] = draft.time.split(':').map(Number);
    const starts = new Date(`${draft.date}T${String(hh).padStart(2,'0')}:${String(mm).padStart(2,'0')}:00`);
    const ends = new Date(starts.getTime() + (draft.duration_min || 60) * 60 * 1000);

    out.bookingToSave = {
      client_id: client.id,
      service_id: draft.service_id,
      starts_at: starts.toISOString(),
      ends_at: ends.toISOString(),
      full_name: draft.full_name,
      phone: draft.phone,
    };
    out.replyText =
      `Готово! Записал тебя:\n` +
      `• Услуга: ${draft.service_title}\n` +
      `• Дата: ${draft.date} ${draft.time}\n` +
      `• Имя: ${draft.full_name}\n` +
      `• Телефон: ${draft.phone}\n\n` +
      `За день и за час пришлю напоминание. Чтобы отменить — /cancel.`;
    reset();
    break;
  }
  default: {
    out.replyText = 'Что-то пошло не так. Напиши /book чтобы начать заново.';
    reset();
  }
}

out.nextStep = step;
out.draft = draft;
return [{ json: out }];
